const body = $input.first().json.body || $input.first().json;

const tenant_id = (body.tenant_id || '').trim();
const text = (body.text || '').trim();
const source_name = (body.source_name || 'Unbenannt').trim();
const source_type = (body.source_type || 'manual').trim();

if (!tenant_id) throw new Error('tenant_id fehlt');
if (!text) throw new Error('text fehlt');
if (text.length < 10) throw new Error('Text zu kurz (min. 10 Zeichen)');

return [{ json: { tenant_id, text, source_name, source_type } }];

const input = $input.first().json;
const text = input.text;

const MAX_CHUNK_SIZE = 500;
const chunks = [];
let remaining = text;

while (remaining.length > 0) {
  let end = Math.min(remaining.length, MAX_CHUNK_SIZE);
  if (end < remaining.length) {
    const lastPeriod = remaining.lastIndexOf('.', end);
    const lastNewline = remaining.lastIndexOf('\n', end);
    const splitAt = Math.max(lastPeriod, lastNewline);
    if (splitAt > MAX_CHUNK_SIZE * 0.3) {
      end = splitAt + 1;
    }
  }
  const chunk = remaining.substring(0, end).trim();
  if (chunk.length > 0) chunks.push(chunk);
  remaining = remaining.substring(end).trim();
}

return [{ json: { ...input, chunks } }];

const validated = $('Text Chunking').first().json;
const embedResponse = $input.first().json;
const chunks = validated.chunks;
const embeddings = embedResponse.embeddings;
const tenant_id = validated.tenant_id;
const text = validated.text;
const source_name = validated.source_name;
const source_type = validated.source_type;

const esc = (s) => s.replace(/'/g, "''");

const chunkVals = chunks.map((c, i) =>
  `((SELECT id FROM new_doc), '${tenant_id}', '${esc(c)}', ${i}, ${Math.ceil(c.length / 4)})`
).join(',\n  ');

const embVals = embeddings.map((emb, i) => {
  const embStr = '[' + emb.join(',') + ']';
  return `((SELECT id FROM new_chunks WHERE chunk_index = ${i}), '${tenant_id}', '${embStr}')`;
}).join(',\n  ');

const sql = `WITH new_source AS (
  INSERT INTO sources (tenant_id, name, source_type, status)
  VALUES ('${tenant_id}', '${esc(source_name)}', '${source_type}', 'completed')
  RETURNING id
),
new_doc AS (
  INSERT INTO documents (source_id, tenant_id, content)
  SELECT id, '${tenant_id}', '${esc(text)}' FROM new_source
  RETURNING id, source_id
),
new_chunks AS (
  INSERT INTO chunks (document_id, tenant_id, content, chunk_index, token_count)
  VALUES ${chunkVals}
  RETURNING id, chunk_index
),
new_embeddings AS (
  INSERT INTO embeddings (chunk_id, tenant_id, embedding)
  VALUES ${embVals}
)
SELECT source_id, id AS document_id FROM new_doc`;

return [{ json: { sql, chunk_count: chunks.length } }];
